```class Solution {
public:
    int subarrayGCD(vector<int>& nums, int k) {
        int count = 0;
        for (int i = 0; i < nums.size(); i++) {
            int gcd_count = 0;
            for (int j = i; j < nums.size(); j++) {
                if (gcd(nums[i], nums[j]) == k) {
                    gcd_count++;
                }
            }
            count += gcd_count;
        }
        return count;
    }

    int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
};
```

